```typescript
import { GlobalEvents } from "@flamework/networking";

// Types used in events
export type CategoryPayload = ...; // infer from usage
export type PayloadSync = ...; // charm-sync payload

interface ServerEvents {
  // Client -> Server
  atomInit: () => void;
  atomUpdate: (payload: CategoryPayload) => void;
  unitAction: (data: { action: string; unit: string }) => void;
  purchaseShopItem: (data: { shopType: string; itemId: string; amount: number }) => void;
  claimDailyReward: () => void;
  createMatch: (settings: { gameMode?: string; privacy?: string; maxPlayers?: number; minPlayers?: number; allowedPlayers?: number[]; customSettings?: string }) => void;
  joinMatch: (matchId: string) => void;
  leaveMatch: () => void;
  listJoinableMatches: () => void;
}

interface ClientEvents {
  // Server -> Client
  atomSync: (payload: unknown) => void;
  createMatchResult: (result: { success: boolean; matchId?: string; error?: string }) => void;
  matchJoined: (matchId: string) => void;
  matchLeft: (matchId: string) => void;
  joinableMatches: (matches: Array<{ id: string; gameMode: string; privacy: string; maxPlayers: number; minPlayers: number; playerCount: number; isLocked: boolean; hostUserId: number }>) => void;
  matchStarted: (matchId: string) => void;
  matchCancelled: (data: { matchId: string; reason: string }) => void;
  notifyPlayer: (data: { color: string; message: string; duration: number }) => void;
}

export const GlobalEvents = Networking.createEvent<ServerEvents, ClientEvents>();
```

Server usage: GlobalEvents.server.eventName.connect((player, ...args) => {})
Server fires to client: GlobalEvents.client.eventName.fire(player, ...args)
Client usage: GlobalEvents.client.eventName.connect((...args) => {})
Client fires to server: GlobalEvents.server.eventName.fire(...args)

